Kết quả thực hiện đoạn chương trình sau là gì? #include #include using namespace std;
int main() {
	double Op1 = 10, Op2 = 5, Res;
	char Op;
	try {
		if (Op != '+' && Op != '-' && Op != '*' && Op != '/')
			throw Op;
		switch(Op) {
			case '+':
				Res = Op1 + Op2;
				break;
			case '-':
				Res = Op1 - Op2;
				break;
			case '*':
				Res = Op1 * Op2;
				break;
			case '/':
				Res = Op1 / Op2;
				break;
		}
		cout << "\n" << Op1 << " " << Op << " "<< Op2 << " = " << Res;
	} catch (const char n) {
		cout << n << " is not a valid operator";
	}
	return 0;
}
